function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    let mustEdges: number[][] = [];
    let optionalEdges: number[][] = [];

    for (const [u, v, s, m] of edges) {
        if (m === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-include edges form a connected graph
    // If not, return -1
    const parent = Array(n).fill(-1);
    const rank = Array(n).fill(1);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false;
        }
        if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
            rank[rootV] += rank[rootU];
        } else {
            parent[rootV] = rootU;
            rank[rootU] += rank[rootV];
        }
        return true;
    }

    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    for (const [u, v, s] of mustEdges) {
        if (!union(u, v)) {
            return -1; // Must-include edges form a cycle
        }
    }

    // Check if all nodes are connected with must-include edges
    const root = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== root) {
            return -1; // Not connected
        }
    }

    // Sort optional edges by strength
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Try to find the maximum possible stability
    let maxStability = 0;

    // Try different possible minimum strengths
    for (let i = 0; i < optionalEdges.length; i++) {
        // Try to include optional edges with strength >= current value
        let usedK = 0;
        const tempParent = [...parent];
        const tempRank = [...rank];

        // Initialize with must-include edges
        for (const [u, v, s] of mustEdges) {
            if (!union(u, v)) {
                // If there's a cycle, skip this attempt
                break;
            }
        }

        // Check if all nodes are connected
        const rootTemp = find(0);
        for (let j = 1; j < n; j++) {
            if (find(j) !== rootTemp) {
                // Not connected, skip this attempt
                break;
            }
        }

        // Try to include optional edges with strength >= current value
        let currentStability = 0;
        for (let j = i; j < optionalEdges.length; j++) {
            const [u, v, s] = optionalEdges[j];
            if (usedK >= k) break;

            // Check if the edge can be included
            if (find(u) !== find(v)) {
                // Include this edge
                union(u, v);
                usedK++;
                currentStability = Math.max(currentStability, s);
            } else {
                // Skip this edge
                continue;
            }
        }

        // Check if all nodes are connected
        const rootFinal = find(0);
        for (let j = 1; j < n; j++) {
            if (find(j) !== rootFinal) {
                // Not connected, skip this attempt
                break;
            }
        }

        if (currentStability > maxStability) {
            maxStability = currentStability;
        }
    }

    return maxStability;
}

